.chat-markdown > :last-child {
  margin-bottom: 0;
}

.chat-markdown p,
.chat-markdown ul,
.chat-markdown ol,
.chat-markdown blockquote,
.chat-markdown pre,
.chat-markdown table {
  margin: 0.65rem 0;
}

.chat-markdown ul {
  padding-left: 1.25rem;
  list-style-type: disc;
}

.chat-markdown ol {
  padding-left: 1.25rem;
  list-style-type: decimal;
}

.chat-markdown ul ul {
  list-style-type: circle;
}

