  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
}

const BUILT_IN_THEMES: Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#f0f0f0",
      accent: "#6366f1",
      sidebar: "#111113",
      editor: "#0d0d0f",
      terminal: "#000000",
      statusBar: "#1a1a1d",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1a1a1a",
      accent: "#4f46e5",
      sidebar: "#f5f5f5",
      editor: "#fafafa",
      terminal: "#1e1e1e",
      statusBar: "#e8e8e8",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#0d1117",
      foreground: "#c9d1d9",
      accent: "#58a6ff",
      sidebar: "#010409",
      editor: "#0d1117",
      terminal: "#000000",
      statusBar: "#161b22",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
];

const THEME_MAP = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

const DEFAULT_THEME_ID = "t3-dark";

export function getTheme(id: string): Theme {
  return THEME_MAP.get(id) ?? (THEME_MAP.get(DEFAULT_THEME_ID) as Theme);
}

export function listThemes(): Theme[] {
  return [...BUILT_IN_THEMES];
}

