import { createElement, Fragment, useCallback, useEffect, useSyncExternalStore } from "react";
import type { ReactNode } from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";
const DEFAULT_THEME_ID = "t3-dark";

let listeners: Array<() => void> = [];
let lastThemeId: string | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/** Migrate old "dark" | "light" | "system" values to named theme IDs. */
function migrateStoredValue(raw: string | null): string {
  if (!raw) return DEFAULT_THEME_ID;
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight") return raw;
  if (raw === "dark") return "t3-dark";
  if (raw === "light") return "t3-light";
  if (raw === "system") return getSystemDark() ? "t3-dark" : "t3-light";
  return DEFAULT_THEME_ID;
}

function getStoredThemeId(): string {
  return migrateStoredValue(localStorage.getItem(STORAGE_KEY));
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Keep the `.dark` class in sync so Tailwind dark-mode variants still work
  const isDark = theme.id !== "t3-light";
  document.documentElement.classList.toggle("dark", isDark);

  // Push theme tokens as CSS custom properties
  const root = document.documentElement;
  const { colors, fontFamily, fontSize } = theme;
  root.style.setProperty("--t3-background", colors.background);
  root.style.setProperty("--t3-foreground", colors.foreground);
  root.style.setProperty("--t3-accent", colors.accent);
  root.style.setProperty("--t3-sidebar", colors.sidebar);
  root.style.setProperty("--t3-editor", colors.editor);
  root.style.setProperty("--t3-terminal", colors.terminal);
  root.style.setProperty("--t3-status-bar", colors.statusBar);
  root.style.setProperty("--t3-font-family", fontFamily);
  root.style.setProperty("--t3-font-size", `${fontSize}px`);

  if (suppressTransitions) {
    // Force reflow so no-transitions takes effect before it's removed
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getTheme(getStoredThemeId()));

function getSnapshot(): string {
  const themeId = getStoredThemeId();
  if (lastThemeId === themeId) return lastThemeId;
  lastThemeId = themeId;
  return lastThemeId;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync theme when changed in another tab
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getTheme(getStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(themeId);

  /** Preserved for backward-compat with DiffWorkerPoolProvider */
  const resolvedTheme: "light" | "dark" = theme.id === "t3-light" ? "light" : "dark";

  const setTheme = useCallback((newThemeId: string) => {
    localStorage.setItem(STORAGE_KEY, newThemeId);
    applyTheme(getTheme(newThemeId), true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, availableThemes } as const;
}

/** Thin provider component — place high in the tree to guarantee the theme
 *  module is imported (and thus applied) before child components render. */
export function ThemeProvider({ children }: { children: ReactNode }) {
  return createElement(Fragment, null, children);
}

