import { useTheme } from "../hooks/useTheme";

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme">
      {availableThemes.map((t) => {
        const selected = theme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            {/* Color preview swatches: background · foreground · sidebar */}
            <span className="flex shrink-0 items-center gap-1" aria-hidden="true">
              <span
                className="size-3 rounded-full ring-1 ring-inset ring-border"
                style={{ background: t.colors.background }}
              />
              <span
                className="size-3 rounded-full ring-1 ring-inset ring-border"
                style={{ background: t.colors.foreground }}
              />
              <span
                className="size-3 rounded-full ring-1 ring-inset ring-border"
                style={{ background: t.colors.sidebar }}
              />
            </span>

            <span className="flex-1 text-sm font-medium">{t.name}</span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

